              </div>

              {/* COLUMN 3: PROCESSES */}
              <div className={`bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden ${!selectedMacro ? 'opacity-50 pointer-events-none' : ''}`}>
                  <div className="p-3 border-b border-slate-100 bg-slate-50 flex justify-between items-center"><h3 className="font-bold text-slate-700 text-xs uppercase tracking-wide">Procesos</h3>{selectedMacro && <button onClick={() => handleAdd('PROCESS')} className="p-1 hover:bg-indigo-100 text-indigo-600 rounded" title="Nuevo Proceso"><Plus size={16}/></button>}</div>
                  <div className="flex-1 overflow-y-auto p-2 space-y-1">
                      {processes.map(proc => (
                          <div key={proc} onClick={() => setSelectedProcess(proc)} className={`flex items-center justify-between p-2 rounded-lg cursor-pointer text-sm transition-colors group ${selectedProcess === proc ? 'bg-purple-50 text-purple-700 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}>
                              <div className="flex items-center gap-2 truncate"><Layers size={16} className={selectedProcess === proc ? 'text-purple-500' : 'text-slate-400'} /><span className="truncate">{proc}</span></div>
                              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={(e) => { e.stopPropagation(); handleRenameStart('PROCESS', proc); }} className="text-slate-400 hover:text-purple-600 p-1"><Edit size={12}/></button>
                                  {canManage && <button onClick={(e) => handleDeleteNode('PROCESS', proc, e)} className="text-slate-400 hover:text-red-600 p-1" title="Eliminar Proceso"><Trash2 size={12}/></button>}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>

              {/* COLUMN 4: MICROPROCESSES */}
              <div className={`bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden ${!selectedProcess ? 'opacity-50 pointer-events-none' : ''}`}>
                  <div className="p-3 border-b border-slate-100 bg-slate-50 flex justify-between items-center"><h3 className="font-bold text-slate-700 text-xs uppercase tracking-wide">Microprocesos</h3>{selectedProcess && <button onClick={() => handleAdd('MICRO')} className="p-1 hover:bg-indigo-100 text-indigo-600 rounded" title="Nuevo Microproceso"><Plus size={16}/></button>}</div>
                  <div className="flex-1 overflow-y-auto p-2 space-y-1">
                      {columnMicros.map(micro => (
                          <div key={micro.docId} className={`flex items-center justify-between p-2 rounded-lg text-sm bg-white border group transition-all ${micro.active === false ? 'border-slate-100 bg-slate-50 text-slate-400 italic' : 'border-slate-100 hover:border-slate-300'}`}>
                              <div className="flex items-center gap-2 truncate"><FileText size={14} className={micro.active === false ? 'text-slate-300' : 'text-slate-400'} /><span className="truncate font-medium">{micro.name}</span></div>
                              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={(e) => { e.stopPropagation(); handleRenameStart('MICRO', micro.name, micro.docId); }} className="text-slate-400 hover:text-indigo-600 p-1 hover:bg-indigo-50 rounded" title="Renombrar Microproceso"><Edit size={14} /></button>
                                  <button onClick={(e) => handleMoveStart(micro, e)} className="text-slate-400 hover:text-indigo-600 p-1 hover:bg-indigo-50 rounded" title="Reubicar (Mover)"><FolderInput size={14} /></button>
                                  <button onClick={(e) => handleToggleStatus(micro.docId, micro.name, micro.active !== false, e)} className={`p-1 rounded transition-colors ${micro.active === false ? 'text-slate-300 hover:text-green-600 hover:bg-green-50' : 'text-slate-300 hover:text-red-500 hover:bg-red-50'}`} title={micro.active === false ? "Reactivar" : "Inactivar"}><Power size={14}/></button>
                                  {canManage && <button onClick={(e) => handleHardDeleteMicro(micro.docId, micro.name, e)} className="p-1 rounded text-slate-300 hover:text-red-600 hover:bg-red-50 transition-colors" title="Eliminar Definitivamente"><Trash2 size={14}/></button>}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* MODALS */}
      {showAddModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center"><h3 className="font-bold text-slate-800">Agregar {addLevel}</h3><button onClick={() => setShowAddModal(false)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button></div>
                <form onSubmit={handleCreateSubmit} className="p-6">
                    <label className="block text-sm font-medium text-slate-700 mb-2">Nombre del {addLevel}</label>
                    <input autoFocus type="text" value={newItemName} onChange={(e) => setNewItemName(e.target.value)} className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder={`Ingrese nombre para nuevo ${addLevel.toLowerCase()}...`} />
                    <div className="flex justify-end gap-2 mt-6"><button type="button" onClick={() => setShowAddModal(false)} className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded text-sm">Cancelar</button><button type="submit" className="px-4 py-2 bg-indigo-600 text-white rounded text-sm font-medium hover:bg-indigo-700">Crear</button></div>
                </form>
            </div>
          </div>
      )}

      {renameMode && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center"><h3 className="font-bold text-slate-800">Renombrar {renameMode.level}</h3><button onClick={() => setRenameMode(null)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button></div>
                <div className="p-6">
                    <label className="block text-sm font-medium text-slate-700 mb-2">Nuevo nombre para "{renameMode.oldName}"</label>
                    <input autoFocus type="text" value={renameValue} onChange={(e) => setRenameValue(e.target.value)} className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                    <div className="flex justify-end gap-2 mt-6">
                        <button onClick={() => setRenameMode(null)} className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded text-sm">Cancelar</button>
                        <button onClick={handleRenameSubmit} disabled={!renameValue.trim() || loading} className="px-4 py-2 bg-indigo-600 text-white rounded text-sm font-medium hover:bg-indigo-700 flex items-center gap-2">
                            {loading && <Loader2 size={14} className="animate-spin"/>} Guardar Cambios
                        </button>
                    </div>
                </div>
            </div>
          </div>
      )}

      {showMoveModal && moveTarget && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center"><h3 className="font-bold text-slate-800 flex items-center gap-2"><FolderInput size={20} className="text-indigo-600"/> Reubicar Microproceso</h3><button onClick={() => setShowMoveModal(false)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button></div>
                  <form onSubmit={handleMoveSubmit} className="p-6">
                      <div className="bg-blue-50 p-3 rounded-lg border border-blue-100 mb-6 text-sm">
                          <span className="text-slate-500">Moviendo:</span> <span className="font-bold text-slate-800 ml-2">{moveTarget.name}</span>
                          <div className="flex items-center gap-2 mt-2 text-xs text-slate-500"><span>Desde:</span><span className="bg-white px-2 py-0.5 rounded border">{moveTarget.currentProject}</span><ChevronRight size={12}/><span className="bg-white px-2 py-0.5 rounded border">{moveTarget.currentMacro}</span><ChevronRight size={12}/><span className="bg-white px-2 py-0.5 rounded border">{moveTarget.currentProcess}</span></div>
                      </div>
                      <div className="space-y-4">
                          <div><label className="block text-xs font-bold text-slate-500 uppercase mb-1">Proyecto Destino</label><select value={targetProject} onChange={(e) => { setTargetProject(e.target.value); setTargetMacro(''); setTargetProcess(''); }} className="w-full p-2.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500">{Object.keys(hierarchy).map(p => <option key={p} value={p}>{p}</option>)}</select></div>
                          <div><label className="block text-xs font-bold text-slate-500 uppercase mb-1">Macroproceso Destino</label><select value={targetMacro} onChange={(e) => { setTargetMacro(e.target.value); setTargetProcess(''); }} disabled={!targetProject} className="w-full p-2.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 disabled:bg-slate-100 disabled:text-slate-400"><option value="">-- Seleccionar --</option>{availableMacros.map(m => <option key={m} value={m}>{m}</option>)}</select></div>
                          <div><label className="block text-xs font-bold text-slate-500 uppercase mb-1">Proceso Destino</label><select value={targetProcess} onChange={(e) => setTargetProcess(e.target.value)} disabled={!targetMacro} className="w-full p-2.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 disabled:bg-slate-100 disabled:text-slate-400"><option value="">-- Seleccionar --</option>{availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}</select></div>
                      </div>
                      <div className="flex justify-end gap-2 mt-8"><button type="button" onClick={() => setShowMoveModal(false)} className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded text-sm font-medium">Cancelar</button><button type="submit" disabled={!targetProcess || loading} className="px-4 py-2 bg-indigo-600 text-white rounded text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2">{loading && <Loader2 size={14} className="animate-spin"/>} Confirmar Reubicación</button></div>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

export default AdminHierarchy;
